 25	import { HelpIcon } from '@patternfly/react-icons';
 26	import {
 27	  AUTO_DNS,
 28	  AUTO_GATEWAY,
 29	  AUTO_ROUTES,
 30	  InterfaceType,
 31	  NodeNetworkConfigurationInterface,
 32	  V1NodeNetworkConfigurationPolicy,
 33	} from '@types';
 34	import { OVN_BRIDGE_MAPPINGS } from '@utils/ovn/constants';
 35	
 36	import BondOptions from './BondOptions';
 37	import { DEFAULT_PREFIX_LENGTH, INTERFACE_TYPE_OPTIONS, NETWORK_STATES } from './constants';
 38	import CopyMAC from './CopyMAC';
 39	import { isOVSBridgeExisting, validateInterfaceName } from './utils';
 40	
 41	export type onInterfaceChangeType = (
 42	  policyInterface: NodeNetworkConfigurationInterface,
 43	  policy: V1NodeNetworkConfigurationPolicy,
 44	) => void;
 45	
 46	type HandleSelectChange = FormSelectProps['onChange'];
 47	
 48	type PolicyInterfaceProps = {
 49	  id: number;
 50	  isInterfaceCreated?: boolean;
 51	  policyInterface?: NodeNetworkConfigurationInterface;
 52	  onInterfaceChange?: (updateInterface: onInterfaceChangeType) => void;
 53	};
 54	
 55	const PolicyInterface: FC<PolicyInterfaceProps> = ({
 56	  id,
 57	  policyInterface,
 58	  onInterfaceChange,
 59	  isInterfaceCreated = true,
 60	}) => {
 61	  const { t } = useNMStateTranslation();
 62	
 63	  const handleStateChange: HandleSelectChange = (event, newState: NETWORK_STATES) => {
 64	    onInterfaceChange((draftInterface) => (draftInterface.state = newState));
 65	  };
 66	
 67	  const handleNameChange = (newName: string) => {
 68	    onInterfaceChange((draftInterface) => (draftInterface.name = newName));
 69	  };
 70	
 71	  const handleTypechange: HandleSelectChange = (event, newType: string) => {
 72	    onInterfaceChange((draftInterface, draftPolicy) => {
 73	      draftInterface.type = newType as InterfaceType;
 74	      !isOVSBridgeExisting(draftPolicy) && delete draftPolicy.spec.desiredState.ovn;
 75	
 76	      if (newType === InterfaceType.LINUX_BRIDGE) {
 77	        delete draftInterface['link-aggregation'];
 78	        draftInterface.bridge = { port: [], options: { stp: { enabled: false } } };
 79	      }
 80	
 81	      if (newType === InterfaceType.OVS_BRIDGE) {
 82	        delete draftInterface['link-aggregation'];
 83	        draftInterface.bridge = { port: [], options: {} };
 84	        if (!draftPolicy?.spec?.desiredState?.ovn) {
 85	          draftPolicy.spec.desiredState.ovn = {
 86	            [OVN_BRIDGE_MAPPINGS]: [],
 87	          };
 88	        }
 89	        draftPolicy.spec.desiredState.ovn[OVN_BRIDGE_MAPPINGS].push({
 90	          bridge: '',
 91	          localnet: '',
 92	          state: 'present',
 93	        });
 94	      }
 95	
 96	      if (newType === InterfaceType.BOND) {
 97	        delete draftInterface.bridge;
 98	        draftInterface['link-aggregation'] = {
 99	          mode: NodeNetworkConfigurationInterfaceBondMode.BALANCE_RR,
100	          port: [],
101	        };
102	      }
103	
104	      if (newType === InterfaceType.ETHERNET) {
105	        delete draftInterface.bridge;
106	        delete draftInterface['link-aggregation'];
107	      }
108	    });
109	  };
110	
111	  const onIP4Change = (checked: boolean) => {
112	    if (checked)
113	      onInterfaceChange(
114	        (draftInterface) =>
115	          (draftInterface.ipv4 = {
116	            enabled: true,
117	            address: [{ ip: '', 'prefix-length': DEFAULT_PREFIX_LENGTH }],
118	          }),
119	      );
120	    else {
121	      onInterfaceChange((draftInterface) => {
122	        delete draftInterface.ipv4;
123	      });
124	    }
125	  };
126	
127	  const onDHCPChange = (checked: boolean) => {
128	    onInterfaceChange((draftInterface) => {
129	      draftInterface.ipv4 = { enabled: true, dhcp: checked };
130	    });
131	  };
132	
133	  const onAddressChange = (value: string) => {
134	    onInterfaceChange((draftInterface) => {
135	      draftInterface.ipv4 = {
136	        enabled: true,
137	        address: [{ ip: value, 'prefix-length': DEFAULT_PREFIX_LENGTH }],
138	      };
139	    });
140	  };
141	
142	  const onPrefixChange = (value: number) => {
143	    onInterfaceChange((draftInterface) => {
144	      if (draftInterface.ipv4.address.length > 0)
145	        draftInterface.ipv4.address[0]['prefix-length'] = value;
146	    });
147	  };
148	
149	  const onSTPChange = (checked: boolean) => {
150	    onInterfaceChange((draftInterface) => {
151	      ensurePath(draftInterface, 'bridge.options');
152	
153	      draftInterface.bridge = {
154	        options: {
155	          stp: { enabled: checked },
156	        },
157	      };
158	    });
159	  };
160	
161	  const handleAggregationChange: HandleSelectChange = (event, aggregationMode: string) => {
162	    onInterfaceChange((draftInterface) => {
163	      ensurePath(draftInterface, 'link-aggregation');
164	      draftInterface['link-aggregation'].mode =
165	        aggregationMode as NodeNetworkConfigurationInterfaceBondMode;
166	    });
167	  };
168	
169	  const onPortChange = (value: string) => {
170	    onInterfaceChange((draftInterface) => {
171	      if (draftInterface.type === InterfaceType.BOND) {
172	        ensurePath(draftInterface, 'link-aggregation.port');
173	
174	        value
175	          ? (draftInterface['link-aggregation'].port = value.split(','))
176	          : delete draftInterface['link-aggregation'].port;
177	      }
178	
179	      if (
180	        draftInterface.type === InterfaceType.LINUX_BRIDGE ||
181	        draftInterface.type === InterfaceType.OVS_BRIDGE
182	      ) {
183	        ensurePath(draftInterface, 'bridge.port');
184	        value
185	          ? (draftInterface.bridge.port = [{ name: value }])
186	          : delete draftInterface.bridge.port;
187	      }
188	    });
189	  };
190	
191	  const nameError = validateInterfaceName(policyInterface?.name);
192	
193	  return (
194	    <>
195	      <FormGroup label={t('Interface name')} isRequired fieldId={`policy-interface-name-${id}`}>
196	        <TextInput
197	          isRequired
198	          id={`policy-interface-name-${id}`}
199	          name={`policy-interface-name-${id}`}
200	          value={policyInterface?.name}
201	          onChange={(_, newValue) => handleNameChange(newValue)}
202	          isDisabled={isInterfaceCreated}
203	        />
204	        {nameError && (
205	          <FormHelperText>
206	            <HelperText>
