245	          id={`policy-interface-ip-${id}`}
246	          isChecked={policyInterface?.ipv4?.enabled}
247	          onChange={(_, newValue) => onIP4Change(newValue)}
248	        />
249	        <div className="pf-u-ml-md pf-u-mt-sm">
250	          {policyInterface?.ipv4 && (
251	            <Flex className="pf-u-mb-md">
252	              <FlexItem>
253	                <Radio
254	                  label={t('IP address')}
255	                  name={`ip-or-dhcp-${id}`}
256	                  id={`ip-${id}`}
257	                  isChecked={!policyInterface?.ipv4?.dhcp}
258	                  onChange={() => onAddressChange('')}
259	                />
260	              </FlexItem>
261	
262	              <FlexItem>
263	                <Radio
264	                  label={t('DHCP')}
265	                  name={`ip-or-dhcp-${id}`}
266	                  id={`dhcp-${id}`}
267	                  isChecked={policyInterface?.ipv4?.dhcp}
268	                  onChange={(_, newValue) => onDHCPChange(newValue)}
269	                />
270	              </FlexItem>
271	            </Flex>
272	          )}
273	          {policyInterface?.ipv4 && !policyInterface?.ipv4?.dhcp && (
274	            <>
275	              <FormGroup
276	                label={t('IPV4 address')}
277	                isRequired
278	                fieldId={`ipv4-address-${id}`}
279	                className="pf-u-mb-md"
280	              >
281	                <TextInput
282	                  value={policyInterface?.ipv4?.address?.[0]?.ip}
283	                  type="text"
284	                  id={`ipv4-address-${id}`}
285	                  onChange={(_, newValue) => onAddressChange(newValue)}
286	                />
287	              </FormGroup>
288	              <FormGroup label={t('Prefix length')} isRequired fieldId={`prefix-length-${id}`}>
289	                <NumberInput
290	                  value={policyInterface?.ipv4?.address?.[0]?.['prefix-length']}
291	                  id={`prefix-length-${id}`}
292	                  onChange={(event) => onPrefixChange(event.currentTarget.valueAsNumber)}
293	                  onMinus={() =>
294	                    onPrefixChange(policyInterface.ipv4.address[0]['prefix-length'] - 1)
295	                  }
296	                  onPlus={() =>
297	                    onPrefixChange(policyInterface.ipv4.address[0]['prefix-length'] + 1)
298	                  }
299	                  min={0}
300	                  max={32}
301	                />
302	              </FormGroup>
303	            </>
304	          )}
305	
306	          {!!policyInterface?.ipv4?.dhcp && (
307	            <>
308	              <Checkbox
309	                label={t('Auto-DNS')}
310	                id={`policy-interface-dns-${id}`}
311	                isChecked={
312	                  policyInterface?.ipv4[AUTO_DNS] === true ||
313	                  policyInterface?.ipv4[AUTO_DNS] === undefined
314	                }
315	                onChange={(_, checked) =>
316	                  onInterfaceChange((draftInterface) => (draftInterface.ipv4[AUTO_DNS] = checked))
317	                }
318	              />
319	              <Checkbox
320	                label={t('Auto-routes')}
321	                id={`policy-interface-routes-${id}`}
322	                isChecked={
323	                  policyInterface?.ipv4[AUTO_ROUTES] === true ||
324	                  policyInterface?.ipv4[AUTO_ROUTES] === undefined
325	                }
326	                onChange={(_, checked) =>
327	                  onInterfaceChange(
328	                    (draftInterface) => (draftInterface.ipv4[AUTO_ROUTES] = checked),
329	                  )
330	                }
331	              />
332	              <Checkbox
333	                label={t('Auto-gateway')}
334	                id={`policy-interface-gateway-${id}`}
335	                isChecked={
336	                  policyInterface?.ipv4[AUTO_GATEWAY] === true ||
337	                  policyInterface?.ipv4[AUTO_GATEWAY] === undefined
338	                }
339	                onChange={(_, checked) =>
340	                  onInterfaceChange(
341	                    (draftInterface) => (draftInterface.ipv4[AUTO_GATEWAY] = checked),
342	                  )
343	                }
344	              />
345	            </>
346	          )}
347	        </div>
348	      </FormGroup>
349	
350	      {policyInterface.type !== InterfaceType.ETHERNET && (
351	        <FormGroup label={t('Port')} fieldId={`policy-interface-port-${id}`}>
352	          <TextInput
353	            value={
354	              policyInterface?.bridge?.port?.[0]?.name ||
355	              policyInterface?.['link-aggregation']?.port?.join(',')
356	            }
357	            type="text"
358	            id={`policy-interface-port-${id}`}
359	            onChange={(_, newValue) => onPortChange(newValue)}
360	          />
361	
362	          {policyInterface.type === InterfaceType.BOND && (
363	            <FormHelperText>
364	              <HelperText>
365	                <HelperTextItem variant="default">
366	                  {t('Use commas to separate ports')}
367	                </HelperTextItem>
368	              </HelperText>
369	            </FormHelperText>
370	          )}
371	        </FormGroup>
372	      )}
373	      {(policyInterface.type === InterfaceType.LINUX_BRIDGE ||
374	        policyInterface.type === InterfaceType.OVS_BRIDGE) && (
375	        <FormGroup fieldId={`policy-interface-stp-${id}`}>
376	          <Checkbox
377	            label={
378	              <Text>
379	                {t('Enable STP')}{' '}
380	                {isInterfaceCreated && (
381	                  <Popover
382	                    aria-label={'Help'}
383	                    bodyContent={() => <div>{t('Edit the STP in the YAML file')}</div>}
384	                  >
385	                    <HelpIcon />
386	                  </Popover>
387	                )}
388	              </Text>
389	            }
390	            id={`policy-interface-stp-${id}`}
391	            isChecked={policyInterface?.bridge?.options?.stp?.enabled !== false}
392	            onChange={(_, newValue) => onSTPChange(newValue)}
393	            isDisabled={isInterfaceCreated}
394	          />
395	        </FormGroup>
396	      )}
397	
398	      {policyInterface.type === InterfaceType.BOND && (
399	        <>
400	          <CopyMAC
401	            id={id}
402	            onInterfaceChange={onInterfaceChange}
403	            policyInterface={policyInterface}
404	          />
405	          <FormGroup
406	            label={t('Aggregation mode')}
407	            isRequired
408	            fieldId={`policy-interface-aggregation-${id}`}
409	          >
410	            <FormSelect
411	              id={`policy-interface-aggregation-${id}`}
412	              onChange={handleAggregationChange}
413	              value={policyInterface?.['link-aggregation']?.mode}
414	            >
415	              {Object.entries(NodeNetworkConfigurationInterfaceBondMode).map(([key, value]) => (
416	                <FormSelectOption key={key} value={value} label={value} />
417	              ))}
418	            </FormSelect>
419	          </FormGroup>
420	          <BondOptions
421	            onInterfaceChange={onInterfaceChange}
422	            policyInterface={policyInterface}
423	            id={id}
424	          />
425	        </>
426	      )}
427	    </>
428	  );
429	};
430	
431	export default PolicyInterface;

